5		module csi_fuzzer #
6		(
7	        parameter integer CSI_FUZZER_WIDTH = 6,
8	        parameter integer IQ_DATA_WIDTH = 16
9		)
10		(
11	        input wire rstn,
12	        input wire clk,
13	        
14	        // input data
15	        input wire [(2*IQ_DATA_WIDTH-1):0] iq,
16	        input wire iq_valid,
17	
18	        // FIR coef of the fuzzer
19	        input wire signed [(CSI_FUZZER_WIDTH-1):0] bb_gain1,
20	        input wire              bb_gain1_rot90_flag,
21	        input wire signed [(CSI_FUZZER_WIDTH-1):0] bb_gain2,
22	        input wire              bb_gain2_rot90_flag,
23	
24	        // output data
25	        output reg [(2*IQ_DATA_WIDTH-1):0] iq_out
26		);
27	    
28	    wire signed [(IQ_DATA_WIDTH-1) : 0] i0;
29	    wire signed [(IQ_DATA_WIDTH-1) : 0] q0;
30	    reg  signed [(IQ_DATA_WIDTH-1) : 0] i1;
31	    reg  signed [(IQ_DATA_WIDTH-1) : 0] q1;
32	    reg  signed [(IQ_DATA_WIDTH-1) : 0] i2;
33	    reg  signed [(IQ_DATA_WIDTH-1) : 0] q2;
34	
35	    reg signed [(CSI_FUZZER_WIDTH+IQ_DATA_WIDTH-1) : 0] tap1_result_i;
36	    reg signed [(CSI_FUZZER_WIDTH+IQ_DATA_WIDTH-1) : 0] tap1_result_q;
37	    reg signed [(CSI_FUZZER_WIDTH+IQ_DATA_WIDTH-1) : 0] tap2_result_i;
38	    reg signed [(CSI_FUZZER_WIDTH+IQ_DATA_WIDTH-1) : 0] tap2_result_q;
39	
40	    assign i0 = iq[  (IQ_DATA_WIDTH-1) : 0];
